Im

export const Routing=()=>{
return<>
<Routes>
<Route path="shop" element={<Shop></Shop>}></Route>
<Route path="cart" element={<Cart></Cart>}></Route>
<Route path="moreDetails/:id" element={<MoreDetails></MoreDetails>}></Route>

</Routes>

</>
}
